final:
module RefModule(
	input clk,
	input reset,
	output reg [2:0] gray_code);

reg [2:0] binary_count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		binary_count <= 3'b000;
	else
		binary_count <= binary_count + 1;
end

always @(binary_count) begin
	gray_code = binary_count ^ (binary_count >> 1);
end

endmodule
